import { useEffect, useState } from "react"

const paymentPlans = [{
    planTitle: '24x',
    planDuration: '24',
    planTag: 'Bestseller',
    id: 'plan-1'
},
{
    planTitle: '12x',
    planDuration: '12',
    planTag: 'Most Popular',
    id: 'plan-2'
},
{
    planTitle: '6x',
    planDuration: '6',
    planTag: 'Balanced',
    id: 'plan-3'
},
{
    planTitle: '3x',
    planDuration: '3',
    planTag: 'Quick Pay',
    id: 'plan-4'
}
]

async function calculateInstallments(totalAmount, activePlan) {
    const startDate = new Date()
    const data = await new Promise((res) => {
        const { planDuration } = activePlan
        const calculatedInstallment = Number(totalAmount) / Number(planDuration)
        const arr = Array.from({ length: planDuration }, (_, i) => {
            const date = new Date(startDate)
            date.setMonth(date.getMonth() + i)
            return { dueDate: date.toISOString().slice(0, 10), dueDateLabel: date.toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" }), dueAmt: calculatedInstallment }
        })
        setTimeout(() => {
            res([...arr])
        }, 1000)
    })
    return data
}
export async function getPlansData() {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            return resolve(paymentPlans)
        }, 1000)
    })
}

export async function getInstallments(totalAmount, activePlan) {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            return resolve(calculateInstallments(totalAmount, activePlan))
        }, 1000)
    })
}

function useData(fn, options) {
    const [resp, setResp] = useState({
        data: null,
        loading: false,
        error: null
    })

    async function fetchData() {
        setResp((prev) => {
            return {
                ...prev,
                loading: true
            }
        })
        try {
            const result = await fn()
            setResp((prev) => {
                return {
                    ...prev,
                    data: result
                }
            })
        } catch (err) {
            setResp((prev) => {
                return {
                    ...prev,
                    error: 'Following error occured:' + err
                }
            })
        } finally {
            setResp((prev) => {
                return {
                    ...prev,
                    loading: false
                }
            })
        }
    }

    function refetch(...args) {
        fetchData(...args)
    }

    useEffect(() => {
        if (!options.loadOnRefetch) {
            fetchData()
        }
    }, [fn, options])

    return { refetch, ...resp }
}

export default useData
